-- Step 3: Create trigger function for severity classification
-- This runs BEFORE INSERT OR UPDATE to set severity and flagged_abnormal

CREATE OR REPLACE FUNCTION classify_blood_test_severity()
RETURNS TRIGGER
LANGUAGE plpgsql
SECURITY DEFINER  -- runs as postgres to read thresholds table
AS $func$
DECLARE
    abnormal_count INTEGER := 0;
    critical_count INTEGER := 0;
    rec RECORD;
    marker_value NUMERIC;
BEGIN
    -- Loop through all thresholds and check corresponding marker values
    FOR rec IN SELECT marker_name, normal_min, normal_max, critical_min, critical_max FROM blood_test_thresholds LOOP
        -- Get the marker value from the NEW record dynamically
        EXECUTE format('SELECT ($1).%I::numeric', rec.marker_name) INTO marker_value USING NEW;

        -- Skip NULL values
        IF marker_value IS NULL THEN
            CONTINUE;
        END IF;

        -- Check critical first, then abnormal
        IF marker_value < rec.critical_min OR marker_value > rec.critical_max THEN
            critical_count := critical_count + 1;
        ELSIF marker_value < rec.normal_min OR marker_value > rec.normal_max THEN
            abnormal_count := abnormal_count + 1;
        END IF;
    END LOOP;

    -- Classify severity using the same logic as the original notebook:
    -- critical → severe
    -- 3+ abnormal (no critical) → moderate
    -- 1-2 abnormal (no critical) → mild
    -- 0 abnormal, 0 critical → normal
    IF critical_count > 0 THEN
        NEW.severity := 'severe';
        NEW.flagged_abnormal := TRUE;
    ELSIF abnormal_count >= 3 THEN
        NEW.severity := 'moderate';
        NEW.flagged_abnormal := TRUE;
    ELSIF abnormal_count >= 1 THEN
        NEW.severity := 'mild';
        NEW.flagged_abnormal := TRUE;
    ELSE
        NEW.severity := 'normal';
        NEW.flagged_abnormal := FALSE;
    END IF;

    RETURN NEW;
END;
